sp_angular_provider.script:
function scmContextmenu() {
    "use strict";
    return {
        restrict: "A",
        link: function (scope, element, attrs) {
            function triggerContextMenu(event) {
                var handled = scope.$eval(attrs.scmContextmenu, {
                    $event: event,
                });

                if (handled) {
                    event.preventDefault();
                    event.stopPropagation();
                    scope.$evalAsync();
                }
            }

            element.on("contextmenu", triggerContextMenu);

            scope.$on("$destroy", function () {
                element.off("contextmenu");
            });
        },
    };
}
